<script setup lang="ts">
    import { useRoute, useRouter } from "vue-router";
    import { ref, watch } from "vue";
    import NavigationMenu from "./NavigationMenu.vue";
    import UserMenu from "./UserMenu.vue";

    const route = useRoute()
    const router = useRouter()

    const name = ref("")
    const navigationMenuOpened = ref(false)
    const userMenuOpened = ref(false)

    watch(() => route.query.name, (n) => name.value = (n as string) ?? "")

    async function onSearchInputKeyDown(event: KeyboardEvent) {
        if (event.key === "Enter")
            if (name.value)
                await router.push(`/store?name=${name.value}`)
            else
                await router.push(`/store`)
    }
</script>

